// Install: npm install graphql-depth-limit
const { ApolloServer } = require('@apollo/server');
const { startStandaloneServer } = require('@apollo/server/standalone');
const depthLimit = require('graphql-depth-limit');
const { GraphQLError } = require('graphql');

// Define GraphQL schema with circular relationships (common pattern)
const typeDefs = `#graphql
  type User {
    id: ID!
    name: String!
    email: String!
    posts: [Post!]!        # One-to-many relationship
    friends: [User!]!      # Circular: User -> User
    following: [User!]!
    followers: [User!]!
  }

  type Post {
    id: ID!
    title: String!
    content: String!
    author: User!          # Circular: Post -> User -> Posts
    comments: [Comment!]!
    tags: [Tag!]!
  }

  type Comment {
    id: ID!
    text: String!
    author: User!          # Circular: Comment -> User -> Posts -> Comments
    post: Post!            # Circular: Comment -> Post -> Comments
    replies: [Comment!]!   # Recursive: Comment -> Comment
  }

  type Tag {
    id: ID!
    name: String!
    posts: [Post!]!        # Circular: Tag -> Posts -> Tags
  }

  type Query {
    user(id: ID!): User
    users(limit: Int = 10, offset: Int = 0): [User!]!
    post(id: ID!): Post
    posts(limit: Int = 10): [Post!]!
  }
`;

// Resolvers implementation (simplified)
const resolvers = {
  Query: {
    user: async (parent, { id }, context) => {
      return context.dataSources.userAPI.getUserById(id);
    },
    users: async (parent, { limit, offset }, context) => {
      return context.dataSources.userAPI.getUsers(limit, offset);
    },
    post: async (parent, { id }, context) => {
      return context.dataSources.postAPI.getPostById(id);
    }
  },
  User: {
    posts: async (parent, args, context) => {
      return context.dataSources.postAPI.getPostsByAuthor(parent.id);
    },
    friends: async (parent, args, context) => {
      return context.dataSources.userAPI.getFriends(parent.id);
    }
  },
  Post: {
    author: async (parent, args, context) => {
      return context.dataSources.userAPI.getUserById(parent.authorId);
    },
    comments: async (parent, args, context) => {
      return context.dataSources.commentAPI.getCommentsByPost(parent.id);
    }
  },
  Comment: {
    author: async (parent, args, context) => {
      return context.dataSources.userAPI.getUserById(parent.authorId);
    },
    post: async (parent, args, context) => {
      return context.dataSources.postAPI.getPostById(parent.postId);
    },
    replies: async (parent, args, context) => {
      return context.dataSources.commentAPI.getReplies(parent.id);
    }
  }
};

// Configure Apollo Server with depth limiting
const MAX_QUERY_DEPTH = 7;

const server = new ApolloServer({
  typeDefs,
  resolvers,

  // Add validation rules including depth limit
  validationRules: [
    // Depth limit rule with custom error handling
    depthLimit(
      MAX_QUERY_DEPTH,
      {
        // Ignore introspection queries (allow __schema, __type)
        ignore: [
          /__schema/,
          /__type/,
          '_service',     // Apollo Federation
          '_entities'     // Apollo Federation
        ]
      },
      (depths) => {
        // Custom error handler - called when depth exceeded
        const maxDepth = Math.max(...Object.values(depths));

        // Log security event
        console.error('SECURITY: Query depth limit exceeded', {
          timestamp: new Date().toISOString(),
          maxDepth,
          limit: MAX_QUERY_DEPTH,
          depths: depths
        });

        // Return user-friendly error
        return new GraphQLError(
          `Query is too complex. Maximum depth is ${MAX_QUERY_DEPTH}, but query depth is ${maxDepth}.`,
          {
            extensions: {
              code: 'QUERY_DEPTH_EXCEEDED',
              maxDepth: MAX_QUERY_DEPTH,
              actualDepth: maxDepth,
              recommendation: 'Reduce query nesting or split into multiple requests'
            }
          }
        );
      }
    )
  ],

  // Additional security settings
  introspection: process.env.NODE_ENV !== 'production', // Disable in prod

  // Custom error formatter to avoid leaking sensitive info
  formatError: (formattedError, error) => {
    // Log full error server-side
    console.error('GraphQL Error:', {
      message: formattedError.message,
      code: formattedError.extensions?.code,
      path: formattedError.path,
      timestamp: new Date().toISOString()
    });

    // Return sanitized error to client
    if (formattedError.extensions?.code === 'QUERY_DEPTH_EXCEEDED') {
      return formattedError; // Safe to return, no sensitive data
    }

    // In production, hide implementation details
    if (process.env.NODE_ENV === 'production') {
      return {
        message: formattedError.message,
        extensions: {
          code: formattedError.extensions?.code || 'INTERNAL_SERVER_ERROR'
        }
      };
    }

    return formattedError;
  }
});

// Start server
startStandaloneServer(server, {
  listen: { port: 4000 },
  context: async ({ req }) => {
    // Add authentication, data sources, etc.
    return {
      // Context for resolvers
    };
  }
}).then(({ url }) => {
  console.log(`🚀 GraphQL Server ready at ${url}`);
  console.log(`✅ Query depth limited to ${MAX_QUERY_DEPTH} levels`);
  console.log(`ℹ️  Introspection ${process.env.NODE_ENV === 'production' ? 'DISABLED' : 'ENABLED'}`);
});

