// Install: npm install graphql-query-complexity
const { ApolloServer } = require('@apollo/server');
const { startStandaloneServer } = require('@apollo/server/standalone');
const { createComplexityPlugin } = require('@escape.tech/graphql-armor-complexity');
const { getComplexity, simpleEstimator, fieldExtensionsEstimator } = require('graphql-query-complexity');
const { GraphQLError } = require('graphql');

// Define schema with @cost directives for field-level complexity
const typeDefs = `#graphql
  # Directive to annotate fields with complexity costs
  directive @cost(
    complexity: Int!
    multipliers: [String!]
    useMultipliers: Boolean
  ) on FIELD_DEFINITION

  type User {
    id: ID! @cost(complexity: 1)
    name: String! @cost(complexity: 1)
    email: String! @cost(complexity: 1)

    # Expensive field: loads all posts from database
    # Cost increases with 'first' argument (multiplier)
    posts(first: Int = 10): [Post!]! @cost(
      complexity: 10,
      multipliers: ["first"],
      useMultipliers: true
    )

    # Very expensive: loads friends and their full data
    friends(first: Int = 10): [User!]! @cost(
      complexity: 20,
      multipliers: ["first"],
      useMultipliers: true
    )

    # Cheap: computed field, no DB query
    fullName: String! @cost(complexity: 1)
  }

  type Post {
    id: ID! @cost(complexity: 1)
    title: String! @cost(complexity: 1)
    content: String! @cost(complexity: 2)

    # Moderate cost: single DB query for author
    author: User! @cost(complexity: 5)

    # Expensive: loads comments with pagination
    comments(first: Int = 10): [Comment!]! @cost(
      complexity: 10,
      multipliers: ["first"],
      useMultipliers: true
    )

    # Cheap: aggregation query (COUNT)
    commentCount: Int! @cost(complexity: 3)
  }

  type Comment {
    id: ID! @cost(complexity: 1)
    text: String! @cost(complexity: 1)
    createdAt: String! @cost(complexity: 1)

    # Moderate cost: loads user
    author: User! @cost(complexity: 5)

    # Moderate cost: loads post
    post: Post! @cost(complexity: 5)

    # Recursive relationship
    replies(first: Int = 10): [Comment!]! @cost(
      complexity: 8,
      multipliers: ["first"],
      useMultipliers: true
    )
  }

  type Query {
    user(id: ID!): User @cost(complexity: 2)

    # Expensive query: loads multiple users
    # Cost scales with 'first' argument
    users(first: Int = 10, offset: Int = 0): [User!]! @cost(
      complexity: 5,
      multipliers: ["first"],
      useMultipliers: true
    )

    post(id: ID!): Post @cost(complexity: 2)

    posts(first: Int = 10): [Post!]! @cost(
      complexity: 5,
      multipliers: ["first"],
      useMultipliers: true
    )

    # Search is very expensive (full-text search)
    searchUsers(query: String!, first: Int = 10): [User!]! @cost(
      complexity: 50,
      multipliers: ["first"],
      useMultipliers: true
    )
  }
`;

// Resolvers (implementation details omitted for brevity)
const resolvers = {
  // ... resolver implementations
};

// Complexity configuration
const MAXIMUM_COMPLEXITY = 1000; // Max query cost

// Custom plugin for query complexity analysis
const queryComplexityPlugin = {
  async requestDidStart() {
    return {
      async didResolveOperation(requestContext) {
        const { schema, document, operationName, request } = requestContext;

        // Calculate query complexity
        const complexity = getComplexity({
          schema,
          operationName,
          query: document,
          variables: request.variables,
          estimators: [
            // Use field extensions (@cost directive)
            fieldExtensionsEstimator(),
            // Fallback to simple estimator
            simpleEstimator({
              defaultComplexity: 1
            })
          ]
        });

        // Check if complexity exceeds limit
        if (complexity > MAXIMUM_COMPLEXITY) {
          // Log security event
          console.error('SECURITY: Query complexity exceeded', {
            timestamp: new Date().toISOString(),
            complexity,
            limit: MAXIMUM_COMPLEXITY,
            operationName,
            query: request.query?.substring(0, 200) // Log first 200 chars
          });

          // Reject query
          throw new GraphQLError(
            `Query is too complex. Maximum complexity is ${MAXIMUM_COMPLEXITY}, but this query has complexity of ${complexity}.`,
            {
              extensions: {
                code: 'QUERY_COMPLEXITY_EXCEEDED',
                maxComplexity: MAXIMUM_COMPLEXITY,
                actualComplexity: complexity,
                recommendation: 'Reduce query depth, remove unnecessary fields, or use pagination with smaller page sizes'
              }
            }
          );
        }

        // Log query cost for high-complexity queries
        if (complexity > MAXIMUM_COMPLEXITY * 0.7) {
          console.warn('High-complexity query detected', {
            complexity,
            limit: MAXIMUM_COMPLEXITY,
            utilizationPercent: (complexity / MAXIMUM_COMPLEXITY * 100).toFixed(1),
            operationName
          });
        }

        // Add complexity info to response extensions (visible in GraphQL Playground)
        requestContext.response.extensions = {
          ...requestContext.response.extensions,
          complexity: {
            cost: complexity,
            limit: MAXIMUM_COMPLEXITY,
            remaining: MAXIMUM_COMPLEXITY - complexity
          }
        };

        // Add to HTTP headers for monitoring
        if (requestContext.response.http) {
          requestContext.response.http.headers.set(
            'X-GraphQL-Query-Cost',
            complexity.toString()
          );
          requestContext.response.http.headers.set(
            'X-GraphQL-Cost-Limit',
            MAXIMUM_COMPLEXITY.toString()
          );
        }
      }
    };
  }
};

// Create Apollo Server with complexity plugin
const server = new ApolloServer({
  typeDefs,
  resolvers,
  plugins: [queryComplexityPlugin],
  introspection: process.env.NODE_ENV !== 'production'
});

startStandaloneServer(server, {
  listen: { port: 4000 }
}).then(({ url }) => {
  console.log(`🚀 GraphQL Server ready at ${url}`);
  console.log(`✅ Query complexity limited to ${MAXIMUM_COMPLEXITY}`);
  console.log(`ℹ️  Field costs defined via @cost directives`);
});

