// Install: npm install @apollo/server-plugin-response-cache graphql-tag
const { ApolloServer } = require('@apollo/server');
const { startStandaloneServer } = require('@apollo/server/standalone');
const { ApolloServerPluginCacheControl } = require('@apollo/server/plugin/cacheControl');
const { GraphQLError } = require('graphql');
const crypto = require('crypto');

// In-memory store for persisted queries (use Redis in production)
const persistedQueries = new Map();

// Manually allowlisted queries (loaded from file system or database)
const ALLOWLISTED_QUERIES = {
  // Query hash (SHA256) -> Query string
  'a1b2c3d4e5f6': `
    query GetUser($id: ID!) {
      user(id: $id) {
        id
        name
        email
      }
    }
  `,
  '9f8e7d6c5b4a': `
    query GetUserPosts($userId: ID!, $first: Int!) {
      user(id: $userId) {
        id
        name
        posts(first: $first) {
          id
          title
          content
        }
      }
    }
  `,
  'hash_for_approved_query_3': `
    query SearchUsers($query: String!, $limit: Int!) {
      searchUsers(query: $query, first: $limit) {
        id
        name
        email
      }
    }
  `
  // Add all approved production queries here
};

// Load allowlist into persisted query store
for (const [hash, query] of Object.entries(ALLOWLISTED_QUERIES)) {
  persistedQueries.set(hash, query);
}

// GraphQL Schema
const typeDefs = `#graphql
  type User {
    id: ID!
    name: String!
    email: String!
    posts(first: Int = 10): [Post!]!
  }

  type Post {
    id: ID!
    title: String!
    content: String!
    author: User!
  }

  type Query {
    user(id: ID!): User
    searchUsers(query: String!, first: Int = 10): [User!]!
  }
`;

// Resolvers
const resolvers = {
  // ... resolver implementations
};

// Custom plugin for persisted query enforcement
const persistedQueryPlugin = {
  async requestDidStart(requestContext) {
    return {
      async didResolveSource({ request, source }) {
        // Extract query from request
        const incomingQuery = source?.body || request.query;

        // Check if request includes persisted query extension
        const extensions = request.extensions;

        if (extensions?.persistedQuery) {
          // Apollo Automatic Persisted Queries (APQ) format
          const { version, sha256Hash } = extensions.persistedQuery;

          if (version !== 1) {
            throw new GraphQLError('Unsupported persisted query version', {
              extensions: { code: 'PERSISTED_QUERY_VERSION_MISMATCH' }
            });
          }

          // Check if hash exists in allowlist
          const persistedQuery = persistedQueries.get(sha256Hash);

          if (persistedQuery) {
            // Hash found in allowlist - return the query
            console.log('Persisted query executed', {
              hash: sha256Hash,
              timestamp: new Date().toISOString()
            });

            // Modify request to use persisted query
            request.query = persistedQuery;
            return;
          } else if (incomingQuery) {
            // Hash not found, but query provided (APQ registration attempt)
            // In production, reject this! Only allow pre-registered queries
            if (process.env.NODE_ENV === 'production') {
              console.error('SECURITY: Attempted APQ registration in production', {
                hash: sha256Hash,
                timestamp: new Date().toISOString(),
                query: incomingQuery.substring(0, 100)
              });

              throw new GraphQLError(
                'Dynamic query registration is disabled in production. Only pre-registered queries are allowed.',
                {
                  extensions: {
                    code: 'PERSISTED_QUERY_NOT_FOUND',
                    hash: sha256Hash
                  }
                }
              );
            } else {
              // In development, allow registration for testing
              const computedHash = crypto
                .createHash('sha256')
                .update(incomingQuery)
                .digest('hex');

              if (computedHash !== sha256Hash) {
                throw new GraphQLError('Query hash mismatch', {
                  extensions: { code: 'PERSISTED_QUERY_HASH_MISMATCH' }
                });
              }

              // Store query for development
              persistedQueries.set(sha256Hash, incomingQuery);
              console.log('Persisted query registered (DEV ONLY)', {
                hash: sha256Hash
              });

              request.query = incomingQuery;
              return;
            }
          } else {
            // Hash not found and no query provided
            throw new GraphQLError(
              'Persisted query not found. Query has not been registered.',
              {
                extensions: {
                  code: 'PERSISTED_QUERY_NOT_FOUND',
                  hash: sha256Hash
                }
              }
            );
          }
        } else {
          // No persisted query extension - ad-hoc query
          if (process.env.NODE_ENV === 'production') {
            // REJECT all ad-hoc queries in production
            console.error('SECURITY: Ad-hoc query blocked in production', {
              timestamp: new Date().toISOString(),
              query: incomingQuery?.substring(0, 100),
              ip: requestContext.request.http?.headers.get('x-forwarded-for')
            });

            throw new GraphQLError(
              'Ad-hoc queries are not allowed in production. Use persisted queries.',
              {
                extensions: {
                  code: 'AD_HOC_QUERY_DISABLED',
                  documentation: 'https://docs.example.com/graphql/persisted-queries'
                }
              }
            );
          } else {
            // Allow ad-hoc queries in development
            console.log('Ad-hoc query executed (DEV ONLY)');
          }
        }
      }
    };
  }
};

const server = new ApolloServer({
  typeDefs,
  resolvers,
  plugins: [
    persistedQueryPlugin,
    ApolloServerPluginCacheControl({ defaultMaxAge: 300 })
  ],
  introspection: process.env.NODE_ENV !== 'production'
});

startStandaloneServer(server, {
  listen: { port: 4000 }
}).then(({ url }) => {
  console.log(`🚀 GraphQL Server ready at ${url}`);
  console.log(`✅ Persisted queries: ${persistedQueries.size} queries allowlisted`);
