// Install: npm install ioredis graphql-query-complexity express-rate-limit rate-limit-redis
const { ApolloServer } = require('@apollo/server');
const { expressMiddleware } = require('@apollo/server/express4');
const express = require('express');
const { json } = require('body-parser');
const Redis = require('ioredis');
const { GraphQLError } = require('graphql');
const { getComplexity, simpleEstimator, fieldExtensionsEstimator } = require('graphql-query-complexity');

// Initialize Redis for distributed rate limiting
const redis = new Redis({
  host: process.env.REDIS_HOST || 'localhost',
  port: process.env.REDIS_PORT || 6379,
  password: process.env.REDIS_PASSWORD,
  retryStrategy: (times) => {
    const delay = Math.min(times * 50, 2000);
    return delay;
  }
});

// Token bucket configuration
const RATE_LIMIT_CONFIG = {
  MAX_TOKENS: 5000,           // Maximum cost budget per window
  REFILL_RATE: 100,           // Tokens added per second
  REFILL_INTERVAL_MS: 1000,   // Refill every 1 second
  WINDOW_SIZE_SEC: 60,        // 60 second sliding window
  AUTHENTICATED_MULTIPLIER: 2, // Authenticated users get 2x budget
  BURST_ALLOWANCE: 1.5        // Allow 1.5x max_tokens for burst traffic
};

// Token Bucket Rate Limiter
class TokenBucketRateLimiter {
  constructor(redis, config) {
    this.redis = redis;
    this.config = config;
  }

  /**
   * Attempt to consume tokens for a query
   * @param {string} identifier - User ID or IP address
   * @param {number} cost - Query complexity cost
   * @param {boolean} isAuthenticated - Whether user is authenticated
   * @returns {Promise<{allowed: boolean, remainingTokens: number, retryAfter: number}>}
   */
  async consume(identifier, cost, isAuthenticated = false) {
    const maxTokens = isAuthenticated 
      ? this.config.MAX_TOKENS * this.config.AUTHENTICATED_MULTIPLIER
      : this.config.MAX_TOKENS;

    const key = `rate_limit:graphql:${identifier}`;
    const now = Date.now();

    // Lua script for atomic token bucket operation
    const script = `
      local key = KEYS[1]
      local max_tokens = tonumber(ARGV[1])
      local refill_rate = tonumber(ARGV[2])
      local cost = tonumber(ARGV[3])
      local now = tonumber(ARGV[4])
      local burst_allowance = tonumber(ARGV[5])

      -- Get current bucket state
      local bucket = redis.call('HMGET', key, 'tokens', 'last_refill')
      local tokens = tonumber(bucket[1]) or max_tokens
      local last_refill = tonumber(bucket[2]) or now

      -- Calculate token refill
      local time_passed_sec = (now - last_refill) / 1000
      local refill_amount = math.floor(time_passed_sec * refill_rate)
      tokens = math.min(max_tokens * burst_allowance, tokens + refill_amount)

      -- Check if enough tokens available
      if tokens >= cost then
        -- Consume tokens
        tokens = tokens - cost
        redis.call('HMSET', key, 'tokens', tokens, 'last_refill', now)
        redis.call('EXPIRE', key, 120)  -- Expire after 2 minutes of inactivity
        return {1, tokens, 0}  -- allowed, remaining, retryAfter
      else
        -- Not enough tokens
        local tokens_needed = cost - tokens
        local retry_after_sec = math.ceil(tokens_needed / refill_rate)
        return {0, tokens, retry_after_sec}  -- not allowed, remaining, retryAfter
      end
    `;

    try {
      const result = await this.redis.eval(
        script,
        1,  // Number of keys
        key,
        maxTokens,
        this.config.REFILL_RATE,
        cost,
        now,
        this.config.BURST_ALLOWANCE
      );

      return {
        allowed: result[0] === 1,
        remainingTokens: result[1],
        retryAfter: result[2]
      };
    } catch (error) {
      console.error('Rate limiter error:', error);
      // Fail open - allow request if Redis is down
      return { allowed: true, remainingTokens: maxTokens, retryAfter: 0 };
    }
  }

  /**
   * Get current bucket status
   */
  async getStatus(identifier) {
    const key = `rate_limit:graphql:${identifier}`;
    const bucket = await this.redis.hmget(key, 'tokens', 'last_refill');

    return {
      tokens: parseFloat(bucket[0]) || this.config.MAX_TOKENS,
      lastRefill: parseInt(bucket[1]) || Date.now()
    };
  }
}

const rateLimiter = new TokenBucketRateLimiter(redis, RATE_LIMIT_CONFIG);

// GraphQL Schema with @cost directives (same as MIT-002)
const typeDefs = `#graphql
  directive @cost(
    complexity: Int!
    multipliers: [String!]
    useMultipliers: Boolean
  ) on FIELD_DEFINITION

  type User {
    id: ID! @cost(complexity: 1)
    name: String! @cost(complexity: 1)
    posts(first: Int = 10): [Post!]! @cost(complexity: 10, multipliers: ["first"], useMultipliers: true)
  }

  type Post {
    id: ID! @cost(complexity: 1)
    title: String! @cost(complexity: 1)
    author: User! @cost(complexity: 5)
    comments(first: Int = 10): [Comment!]! @cost(complexity: 10, multipliers: ["first"], useMultipliers: true)
  }

  type Comment {
    id: ID! @cost(complexity: 1)
    text: String! @cost(complexity: 1)
    author: User! @cost(complexity: 5)
  }

  type Query {
    user(id: ID!): User @cost(complexity: 2)
    users(first: Int = 10): [User!]! @cost(complexity: 5, multipliers: ["first"], useMultipliers: true)
  }
`;

const resolvers = {
  // ... resolver implementations
};

// Apollo Server plugin for cost-based rate limiting
const costBasedRateLimitPlugin = {
  async requestDidStart(requestContext) {
    return {
      async didResolveOperation(ctx) {
        const { schema, document, operationName, request, contextValue } = ctx;

        // Get user identifier (user ID if authenticated, IP if not)
        const identifier = contextValue.userId || contextValue.req.ip || 'anonymous';
        const isAuthenticated = !!contextValue.userId;

        // Calculate query complexity
        const complexity = getComplexity({
          schema,
          operationName,
          query: document,
          variables: request.variables,
          estimators: [
            fieldExtensionsEstimator(),
            simpleEstimator({ defaultComplexity: 1 })
          ]
        });

        // Apply rate limiting based on query cost
        const rateLimitResult = await rateLimiter.consume(
          identifier,
          complexity,
          isAuthenticated
        );

        if (!rateLimitResult.allowed) {
          // Log rate limit violation
          console.warn('Rate limit exceeded', {
            timestamp: new Date().toISOString(),
            identifier,
            queryCost: complexity,
            remainingBudget: rateLimitResult.remainingTokens,
            retryAfter: rateLimitResult.retryAfter,
            operationName
          });

          // Reject request
          throw new GraphQLError(
            `Query cost budget exceeded. Try again in ${rateLimitResult.retryAfter} seconds.`,
            {
              extensions: {
                code: 'RATE_LIMIT_EXCEEDED',
                queryCost: complexity,
                remainingBudget: Math.floor(rateLimitResult.remainingTokens),
                retryAfter: rateLimitResult.retryAfter,
                maxBudget: isAuthenticated 
                  ? RATE_LIMIT_CONFIG.MAX_TOKENS * RATE_LIMIT_CONFIG.AUTHENTICATED_MULTIPLIER
                  : RATE_LIMIT_CONFIG.MAX_TOKENS,
                refillRate: RATE_LIMIT_CONFIG.REFILL_RATE,
                help: 'Reduce query complexity, use pagination, or wait for budget to refill'
              }
            }
          );
        }

        // Log query cost for monitoring
        console.log('GraphQL query executed', {
          identifier,
          complexity,
          remainingTokens: Math.floor(rateLimitResult.remainingTokens),
          operationName,
          isAuthenticated
        });

        // Add rate limit info to response
        ctx.response.extensions = {
          ...ctx.response.extensions,
          rateLimit: {
            cost: complexity,
            remaining: Math.floor(rateLimitResult.remainingTokens),
            resetIn: Math.ceil(rateLimitResult.remainingTokens / RATE_LIMIT_CONFIG.REFILL_RATE)
          }
        };

        // Add to HTTP headers
        if (ctx.response.http) {
          ctx.response.http.headers.set('X-RateLimit-Cost', complexity.toString());
          ctx.response.http.headers.set('X-RateLimit-Remaining', Math.floor(rateLimitResult.remainingTokens).toString());
          ctx.response.http.headers.set('X-RateLimit-Reset', Math.ceil(rateLimitResult.remainingTokens / RATE_LIMIT_CONFIG.REFILL_RATE).toString());
        }
      }
    };
  }
};

// Create Apollo Server
const server = new ApolloServer({
  typeDefs,
  resolvers,
  plugins: [costBasedRateLimitPlugin]
});

// Express app setup
const app = express();

server.start().then(() => {
  app.use(
    '/graphql',
    json(),
    expressMiddleware(server, {
      context: async ({ req }) => {
        // Extract user from JWT or use IP
        const token = req.headers.authorization?.split(' ')[1];
        const userId = token ? verifyJWT(token)?.userId : null;

        return {
          req,
          userId,
          isAuthenticated: !!userId
        };
      }
    })
  );

  const PORT = 4000;
  app.listen(PORT, () => {
    console.log(`🚀 GraphQL Server ready at http://localhost:${PORT}/graphql`);
    console.log(`✅ Cost-based rate limiting enabled`);
    console.log(`   Max budget: ${RATE_LIMIT_CONFIG.MAX_TOKENS} (${RATE_LIMIT_CONFIG.MAX_TOKENS * RATE_LIMIT_CONFIG.AUTHENTICATED_MULTIPLIER} for authenticated users)`);
    console.log(`   Refill rate: ${RATE_LIMIT_CONFIG.REFILL_RATE} tokens/second`);
  });
});

