// GraphQL DoS detection
// Data source: APM or application logs via Filebeat
url.path: "/graphql" AND (
  (
    // High query complexity
    http.response.headers.x-graphql-query-cost: >1000
  ) OR (
    // Query depth exceeded
    graphql.error.extensions.code: "QUERY_DEPTH_EXCEEDED"
  ) OR (
    // Query complexity exceeded  
    graphql.error.extensions.code: "QUERY_COMPLEXITY_EXCEEDED"
  ) OR (
    // Rate limit exceeded
    graphql.error.extensions.code: "RATE_LIMIT_EXCEEDED"
  ) OR (
    // Slow queries
    event.duration: >5000000000
  ) OR (
    // Server errors during GraphQL execution
    (http.response.status_code: >=500 AND error.message: (*timeout* OR *memory* OR *connection*))
  )
)

